`debounce` delays invoking a function until a specified wait time has elapsed since the last time it was called, which is useful for rate-limiting events like keystrokes or window resizing.

```javascript
function debounce(fn, wait) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(this, args), wait);
  };
}

// Example usage:
const logSearch = debounce((query) => {
  console.log('Searching for:', query);
}, 300);

logSearch('h');
logSearch('he');
logSearch('hel');
logSearch('hello'); // Only this call will log, 300ms after the last invocation.
```
